def is_career_milestone(year):
    milestones = {
        2003: "Uncapped debut against Barbarians",
        2004: "First capped appearance (scored a try vs Italy)",
        2014: "Joined Yorkshire Carnegie",
        2016: "Retired from rugby"
    }
    return milestones.get(year, f"No major milestone in {year}")

# Example usage:
print(is_career_milestone(2004))  # Output: First capped appearance (scored a try vs Italy)
print(is_career_milestone(2010))  # Output: No major milestone in 2010
